        "bio_item_92": "10x Klejnot Zawiści",
        "bio_reward_92": "Wybór: +1000 HP / +120 Obrona / +51 Atak",
        "bio_item_94": "20x Klejnot Mądrości",
        "bio_reward_94": "Wybór: +1100 HP / +140 Obrona / +60 Atak",
        "section_biologist_footer": "Nie zapomnij odebrać końcowej nagrody u Baek-Go w pierwszym mieście po każdym zakończonym badaniu.",
        "section_pets_title": "System Zwierzaków",
        "section_pets_p1": "Zwierzaki w naszym świecie to nie tylko dodatki estetyczne, ale potężni towarzysze, którzy rosną razem z Tobą. W przeciwieństwie do powszechnych systemów, nasz system zwierzaków jest przejrzysty i skupiony na płynnym rozwoju bez zbędnych komplikacji.",
        "section_pets_subtitle1": "Wykluwanie i Opieka",
        "section_pets_hatch_p1": "Wszystko zaczyna się od zdobycia jaja z odpowiedniego bossa. Po wykluciu (naciskając klawisz P lub przez panel szybkiego dostępu), Twój zwierzak otrzyma losowe bonusy startowe do HP, Obrony i SP.",
        "pet_feature_stamina": "Inteligentna Wytrzymałość: Czas trwania zwierzaka upływa tylko wtedy, gdy jest on aktywnie przywołany.",
        "pet_feature_loyalty": "Wyjątkowy Towarzysz: Zwierzaki są niezbywalne i pozostają wiernie przy swoim właścicielu.",
        "section_pets_subtitle2": "Inkubator",
        "section_pets_incubator_p1": "Gdy klikniesz prawym przyciskiem myszy na jajo, otworzy się okno Inkubatora. Tutaj możesz wybrać imię dla swojego nowego towarzysza (od 4 do 20 znaków). Po uiszczeniu opłaty w wysokości 100 000 Gold, zwierzak wykluwa się i jest gotowy do przywołania.",
        "section_pets_showcase_title": "Dostępne Zwierzaki",
        "pet_monkey": "Małpiszon",
        "pet_spider": "Pająk",
        "pet_razador": "Razador",
        "pet_nemere": "Nemere",
        "pet_meley": "Meley",
        "pet_nessie": "Nessie (Hydra)",
        "section_pets_subtitle3": "Doświadczenie i Poziomy",
        "section_pets_exp_p1": "Twój zwierzak może osiągnąć nawet 120 poziom. Zdobywa doświadczenie automatycznie podczas zabijania potworów, jeśli jest przywołany. Poziomy rosną płynnie bez konieczności przeprowadzania złożonych ewolucji czy etapów rozwojowych.",
        "section_pets_exp_p2": "Oprócz czerwonych kul doświadczenia dostępna jest również niebieska kula, którą możesz napełnić, \"poświęcając\" niepotrzebne elementy ekwipunku, co przyspieszy wzrost Twojego towarzysza.",
        "section_pets_skills_title": "Umiejętności Zwierzaka",
        "section_pets_skills_p1": "Każdy zwierzak może nauczyć się do 3 unikalnych umiejętności (pasywnych i aktywnych).",
        "pet_skill_training": "Trening",
        "pet_skill_training_desc": "Umiejętności są nauczane i ulepszane za pomocą odpowiednich książek. Trening trwa do poziomu 20.",
        "pet_skill_examples": "Przykłady Umiejętności",
        "skill_berserker": "Berserk",
        "skill_resistance": "Odporność",
        "skill_vampirism": "Wampiryzm",
        "skill_immortality": "Nieśmiertelność",
        "section_pets_footer": "Wskazówka: Aby przywrócić wytrzymałość (czas), użyj Batonów Proteinowych.",
        "pet_dual_info_title": "Kombinacja Zwierzaków",
        "pet_dual_info_desc": "Oprócz opisanego powyżej systemu Levelable Pet, w grze wciąż dostępny jest klasyczny system zwierzaków. Oznacza to, że gracz może mieć przywołane dwa różne rodzaje zwierzaków jednocześnie i czerpać korzyści z bonusów obu systemów naraz.",
        "section_mounts_title": "System Wierzchowców",
        "section_mounts_p1": "Nasz system wierzchowców został zaprojektowany z myślą o maksymalnej płynności i komforcie podczas podróży przez świat Lorderonu.",
        "section_mounts_subtitle1": "Twój Wierny Towarzysz",
        "section_mounts_desc_p1": "Po założeniu odpowiedniej pieczęci, wierzchowiec pojawi się u Twego boku. Będzie podążał za Tobą na każdym kroku, gotowy do natychmiastowego dosiądnięcia.",
        "mount_feature_flow": "Płynność: System działa na tej samej zasadzie co klasyczny koń, pozwalając na błyskawiczne i płynne wsiadanie oraz zsiadanie.",
        "mount_feature_dynamic": "Dynamika: Wierzchowiec podąża za Tobą wszędzie, gdzie idziesz pieszo, więc jest zawsze pod ręką do szybkiej podróży.",
        "mount_feature_style": "Styl i Moc: Oprócz szybszego poruszania się, wierzchowce zapewniają również dodatkowe bonusy dla Twojej postaci.",
        "section_mounts_tip": "Wskazówka: Możesz używać standardowych skrótów klawiszowych, do których jesteś przyzwyczajony przy koniu (Ctrl+G / Ctrl+H), aby wsiadać i zsiadać.",
        "section_mounts_img_caption": "Podgląd systemu wierzchowców w akcji",
        "section_pvp_skills_title": "Umiejętności PvP",
        "section_pvp_skills_p1": "Wkrocz w nową erę walki z 7. i 8. umiejętnością. Te pasywne umiejętności pozwalają Ci albo zminimalizować obrażenia od najsilniejszych czarów przeciwników, albo wręcz przeciwnie – drastycznie zwiększyć moc Twoich własnych ataków.",
        "skill_ward_title": "7. Umiejętność: Odporność (Ward)",
        "skill_ward_desc": "Pozwala zmniejszyć obrażenia od jednego konkretnego czaru. Każdy gracz może wybrać dowolną odporność z listy 9 umiejętności.",
        "table_lv": "Poziom",
        "table_dmg_reduction": "Redukcja Obrażeń",
        "skill_boost_title": "8. Umiejętność: Wzmocnienie (Boost)",
        "skill_boost_desc": "Zwiększa obrażenia Twojego własnego głównego czaru. Umiejętność tę można zdobyć dopiero po rozwinięciu 7. umiejętności do poziomu P.",
        "table_atk_increase": "Wzrost Ataku",
        "section_pvp_upgrade_title": "System Ulepszania",
        "section_pvp_upgrade_p1": "Ulepszanie 7. i 8. umiejętności przebiega podobnie do standardowych umiejętności, ale przy użyciu specyficznych przedmiotów:",
        "upgrade_step_1": "1 - M1: Użycie punktów umiejętności lub specjalnych ksiąg badań.",
        "upgrade_step_2": "M1 - G1: Czytanie 55 sztuk cennych ksiąg danej umiejętności.",
        "upgrade_step_3": "G1 - P: Trening przy użyciu Kamienia Duchowego+ (zużywa punkty rangi).",
        "section_pvp_list_title": "Dostępne Umiejętności",
