        "pet_meley": "Meley",
        "pet_nessie": "Nessie (Hydra)",
        "section_pets_subtitle3": "Deneyim ve Seviyeler",
        "section_pets_exp_p1": "Evcil hayvanınız 120. seviyeye kadar ulaşabilir. Çağrılmış durumdaysa canavarları öldürürken otomatik olarak deneyim kazanır. Seviyeler, karmaşık evrimlere veya gelişim aşamalarına gerek kalmadan sorunsuz bir şekilde artar.",
        "section_pets_exp_p2": "Kırmızı deneyim kürelerine ek olarak, ihtiyaç duyulmayan ekipman eşyalarını \"feda ederek\" doldurabileceğiniz ve yoldaşınızın büyümesini hızlandıracak mavi bir küre de vardır.",
        "section_pets_skills_title": "Evcil Hayvan Becerileri",
        "section_pets_skills_p1": "Her evcil hayvan 3 adede kadar benzersiz beceri (pasif ve aktif) öğrenebilir.",
        "pet_skill_training": "Eğitim",
        "pet_skill_training_desc": "Beceriler uygun kitaplar kullanılarak öğrenilir ve geliştirilir. Eğitim 20. seviyeye kadar devam eder.",
        "pet_skill_examples": "Beceri Örnekleri",
        "skill_berserker": "Berserker",
        "skill_resistance": "Direniş",
        "skill_vampirism": "Vampirlik",
        "skill_immortality": "Ölümsüzlük",
        "section_pets_footer": "İpucu: Dayanıklılığı (süreyi) geri kazanmak için Protein Barları kullanın.",
        "pet_dual_info_title": "Evcil Hayvan Kombinasyonu",
        "pet_dual_info_desc": "Yukarıda açıklanan Seviyelendirilebilir Evcil Hayvan sistemine ek olarak, klasik evcil hayvan sistemi de oyunda hala mevcuttur. Bu, bir oyuncunun aynı anda iki farklı evcil hayvan türünü çağırmış olabileceği ve böylece her iki sistemin bonuslarından aynı anda yararlanabileceği anlamına gelir.",
        "section_mounts_title": "Binek Sistemi",
        "section_mounts_p1": "Binek sistemimiz, Lorderon dünyasındaki seyahatleriniz sırasında maksimum akıcılık ve konfor için tasarlanmıştır.",
        "section_mounts_subtitle1": "Sadık Yoldaşınız",
        "section_mounts_desc_p1": "İlgili mühürü kuşandıktan sonra binek yanınızda belirecektir. Hemen binmeye hazır bir şekilde her adımınızda sizi takip edecektir.",
        "mount_feature_flow": "Akıcılık: Sistem, klasik bir atla aynı prensipte çalışır ve şimşek hızında, sorunsuz binme ve inmeyi sağlar.",
        "mount_feature_dynamic": "Dinamizm: Binek, yaya olarak gittiğiniz her yerde sizi takip eder, böylece hızlı seyahat için her zaman elinizin altındadır.",
        "mount_feature_style": "Stil ve Güç: Daha hızlı hareket etmenin yanı sıra binekler karakteriniz için ek bonuslar da sağlar.",
        "section_mounts_tip": "İpucu: Binmek ve inmek için ata alışık olduğunuz standart klavye kısayollarını (Ctrl+G / Ctrl+H) kullanabilirsiniz.",
        "section_mounts_img_caption": "Binek sisteminin işleyişine dair önizleme",
        "section_pvp_skills_title": "PvP Becerileri",
        "section_pvp_skills_p1": "7. ve 8. becerilerle yeni bir savaş çağına girin. Bu pasif beceriler, rakiplerinizin en güçlü büyülerinden gelen hasarı en aza indirmenize veya tam tersine kendi saldırılarınızın gücünü büyük ölçüde artırmanıza olanak tanır.",
        "skill_ward_title": "7. Beceri: Misilleme (Ward)",
        "skill_ward_desc": "Belirli bir büyüden gelen hasarı azaltmanıza olanak tanır. Her oyuncu 9 becerilik bir listeden herhangi bir misillemeyi seçebilir.",
        "table_lv": "Seviye",
        "table_dmg_reduction": "Hasar Azaltma",
        "skill_boost_title": "8. Beceri: Güçlendirme (Boost)",
        "skill_boost_desc": "Kendi ana büyünüzün hasarını artırır. Bu beceri ancak 7. beceri P seviyesine ulaştıktan sonra elde edilebilir.",
        "table_atk_increase": "Saldırı Artışı",
        "section_pvp_upgrade_title": "Yükseltme Sistemi",
        "section_pvp_upgrade_p1": "7. ve 8. becerilerin yükseltilmesi standart becerilere benzer şekilde ancak belirli eşyalar kullanılarak ilerler:",
        "upgrade_step_1": "1 - M1: Beceri puanlarının veya özel araştırma kitaplarının kullanımı.",
        "upgrade_step_2": "M1 - G1: Verilen becerinin 55 adet değerli kitabının okunması.",
        "upgrade_step_3": "G1 - P: Ruh Taşı+ kullanarak eğitim (derece puanı tüketir).",
